def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf if (capacity < 0 or item > 0) else 0
            continue
        ratio = item / capacity if capacity != 0 else np.inf
        if ratio < 0:
            priorities[i] = np.inf
            continue
        complexity_score = 0.0
        interaction_penalty = 1.0
        chaos_factor = 0.0
        dynamic_decay = 1.0
        adaptive_bonus = 0.0
        surge = 0.0
        if item == 0 and capacity > 0:
            priorities[i] = 0
            continue
        if ratio > 5:
            for a in range(1, 6):
                for b in range(1, 4):
                    chaos_factor += ((ratio ** (a + b)) / (a * b + 1)) * ((-1) ** (a + b))
            for c in range(1, 5):
                dynamic_decay *= (1 - 1 / (ratio + c + 3)) ** (0.5 + 0.1 * c)
            surge = (ratio ** 7) / 10 + chaos_factor
            if item > capacity * 6:
                surge *= 4
            else:
                surge *= 2.5
            priority_score = surge * dynamic_decay
        elif 3 < ratio <= 5:
            for x in range(1, 10):
                sign = (-1) ** (x + 1)
                interaction_penalty += sign * (ratio ** (x/2)) / (x + 1)
            for y in range(1, 6):
                dynamic_decay *= (1 - 1 / (y + ratio * 0.8 + 2))
            priority_score = abs(interaction_penalty) * dynamic_decay * 15
            if ratio > 4.5:
                for z in range(1, 4):
                    adaptive_bonus += (ratio ** (z / 2)) / (z + 2)
                priority_score += adaptive_bonus * 5
        elif 1.5 < ratio <= 3:
            temp = 0.0
            for p in range(1, 15):
                factor = p ** 1.1 + 2
                if p % 3 == 0:
                    temp += ((-1) ** (p+1)) * (ratio ** p) / factor
                else:
                    temp -= ((-1) ** (p)) * (ratio ** (p/1.5)) / factor
            multiplier = 20 if ratio < 2 else 12
            priority_score = abs(temp) * multiplier
            if ratio > 2.7:
                extra = 0.0
                for m in range(1, 8):
                    extra += (ratio ** (m/1.5)) / (m + 4)
                priority_score += extra * 3
        elif 0 < ratio <= 1.5:
            temp_score = 0.0
            for p in range(1, 20):
                divisor = p * (3 if p % 2 == 0 else 5)
                if p % 5 == 0:
                    temp_score += (ratio ** p) / divisor
                elif p % 4 == 0:
                    temp_score -= (ratio ** p) / (divisor * 1.5)
                else:
                    temp_score += ((-1) ** p) * (ratio ** p) / divisor
            if ratio < 0.1:
                multiplier = 40
            elif ratio < 0.5:
                multiplier = 25
            elif ratio < 1.0:
                multiplier = 12
            else:
                multiplier = 7
            priority_score = abs(temp_score) * multiplier
            if ratio > 1.25:
                penalty_extra = 0.0
                for n in range(1, 10):
                    penalty_extra += (ratio ** n) / (n + 2)
                priority_score += penalty_extra * 3
        else:
            priority_score = 0 if item == 0 else np.inf
        capacity_factor = 1.0
        for z in range(1, 5):
            capacity_factor *= (1 + (z**2) / (capacity + z))
        priority_score *= capacity_factor
        if ratio > 0 and ratio < 0.5 and capacity < 10:
            surge_penalty = 0.0
            for s in range(1, 6):
                surge_penalty += ((ratio ** s) / (s + capacity))
            priority_score += surge_penalty * 5
        priorities[i] = priority_score if priority_score >= 0 else np.inf
    return priorities
